def save_all():
    """Save all regions from collected dumps."""
    # Build flat memory image
    mem = bytearray(0x10000)
    for addr, data in sorted(dumps.items()):
        for i, b in enumerate(data):
            mem[addr + i] = b

    # Define output regions
    regions = [
        (0x0000, 0x0100, "zeropage.bin"),
        (0x0600, 0x0700, "page6_irq.bin"),
        (0x0700, 0x0800, "page7_luts.bin"),
        (0x0800, 0x0D00, "engine_and_tables.bin"),
        (0x0D00, 0x0F00, "music_and_data.bin"),
        (0x0F00, 0x1200, "level_map_part1.bin"),
        # Large data regions will be added as they're dumped
    ]

    for start, end, filename in regions:
        # Check if we actually have data for this region
        has_data = False
        for addr in dumps:
            if addr < end and addr + len(dumps[addr]) > start:
                has_data = True
                break
        if not has_data:
            continue

        filepath = os.path.join(OUTPUT_DIR, filename)
        with open(filepath, "wb") as f:
            f.write(bytes(mem[start:end]))
        print(f"  {filepath}: ${start:04X}-${end-1:04X} ({end-start} bytes)")

    # Save full memory image
    filepath = os.path.join(OUTPUT_DIR, "full_memory.bin")
    with open(filepath, "wb") as f:
        f.write(bytes(mem))
    print(f"  {filepath}: full 64KB")


if __name__ == "__main__":
    print(f"Have {len(dumps)} memory pages")
    save_all()
